"""Tests for context menu state operations.

Tests the state mutations triggered by right-click menu actions:
live session Hide/Clear State, ghost Dismiss, and row right-click dispatch.
"""

from claude_dashboard.config import StatusState
from claude_dashboard.controller import _AgentEntry, _SessionEntry
from claude_dashboard.session import SessionInfo


def _make_session(*, pid: int = 1000, cwd: str = "/tmp/test") -> SessionInfo:
    return SessionInfo(pid=pid, session_id="test-sid", cwd=cwd, started_at=0)


class TestLiveContextMenuHide:
    """Test Hide action from live session context menu."""

    def test_hide_sets_hidden_true(self):
        entry = _SessionEntry(_make_session())
        assert entry.hidden is False
        entry.hidden = True
        assert entry.hidden is True

    def test_hide_preserves_state(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.PERMISSION_REQUIRED
        entry.hidden = True
        assert entry.state == StatusState.PERMISSION_REQUIRED

    def test_hide_preserves_agents(self):
        entry = _SessionEntry(_make_session())
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        entry.hidden = True
        assert len(entry.agents) == 1


class TestLiveContextMenuClearState:
    """Test Clear State action from live session context menu."""

    def test_clear_state_resets_to_idle(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.PERMISSION_REQUIRED
        entry.state = StatusState.IDLE
        entry.agents.clear()
        assert entry.state == StatusState.IDLE

    def test_clear_state_removes_all_agents(self):
        entry = _SessionEntry(_make_session())
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.WORKING)
        entry.agents["a2"] = _AgentEntry(agent_id="a2", state=StatusState.PERMISSION_REQUIRED)
        entry.agents.clear()
        assert len(entry.agents) == 0

    def test_clear_state_effective_state_becomes_idle(self):
        entry = _SessionEntry(_make_session())
        entry.state = StatusState.WORKING
        entry.agents["a1"] = _AgentEntry(agent_id="a1", state=StatusState.PERMISSION_REQUIRED)
        assert entry.effective_state == StatusState.PERMISSION_REQUIRED
        entry.state = StatusState.IDLE
        entry.agents.clear()
        assert entry.effective_state == StatusState.IDLE

    def test_clear_state_preserves_flagged(self):
        entry = _SessionEntry(_make_session())
        entry.flagged = True
        entry.state = StatusState.PERMISSION_REQUIRED
        entry.state = StatusState.IDLE
        entry.agents.clear()
        assert entry.flagged is True

    def test_clear_state_preserves_hidden(self):
        entry = _SessionEntry(_make_session())
        entry.hidden = True
        entry.state = StatusState.PERMISSION_REQUIRED
        entry.state = StatusState.IDLE
        entry.agents.clear()
        assert entry.hidden is True


class TestGhostContextMenuDismiss:
    """Test Dismiss action from ghost context menu."""

    def test_dismiss_removes_from_sessions(self):
        sessions: dict[int, _SessionEntry] = {}
        entry = _SessionEntry(_make_session(pid=-1))
        entry.unattached = True
        sessions[-1] = entry
        sessions.pop(-1, None)
        assert -1 not in sessions

    def test_dismiss_preserves_other_sessions(self):
        sessions: dict[int, _SessionEntry] = {}
        sessions[-1] = _SessionEntry(_make_session(pid=-1))
        sessions[-1].unattached = True
        sessions[1000] = _SessionEntry(_make_session(pid=1000, cwd="/tmp/other"))
        sessions.pop(-1, None)
        assert 1000 in sessions
        assert -1 not in sessions


class TestRowRightClickDispatch:
    """Test that right-click dispatches correctly based on unattached status."""

    def test_unattached_entry_routes_to_ghost_menu(self):
        entry = _SessionEntry(_make_session())
        entry.unattached = True
        assert entry.unattached is True

    def test_attached_entry_routes_to_live_menu(self):
        entry = _SessionEntry(_make_session())
        entry.unattached = False
        assert entry.unattached is False

    def test_dispatch_checks_unattached_field(self):
        """The dispatch decision is solely based on entry.unattached."""
        ghost = _SessionEntry(_make_session(pid=-1))
        ghost.unattached = True
        live = _SessionEntry(_make_session(pid=1000))
        live.unattached = False
        # Ghost and live are distinguished only by unattached flag
        assert ghost.unattached != live.unattached
